const html = items[0].json.data;

if (!html) {
    throw new Error("No se recibió contenido HTML del nodo anterior.");
}

// 1. Extraer la TASA
const regexDolar = /<div id="dolar"[\s\S]*?<strong>\s*([\d.,]+)\s*<\/strong>/i;
const matchTasa = html.match(regexDolar);
if (!matchTasa || !matchTasa[1]) {
    throw new Error("No se pudo encontrar la tasa del dólar en el HTML.");
}
const tasaString = matchTasa[1].replace(/\./g, '').replace(',', '.');
const tasaNumerica = parseFloat(tasaString);

// 2. Extraer la FECHA DE VIGENCIA (Sigue extrayendo el formato ISO completo)
const regexFecha = /<div id="dolar"[\s\S]*?Fecha Valor:[\s\S]*?content="([^"]+)"/i;
const matchFecha = html.match(regexFecha);
if (!matchFecha || !matchFecha[1]) {
    throw new Error("No se pudo encontrar la fecha de vigencia en el HTML. La estructura de la página del BCV probablemente ha cambiado.");
}
const fechaVigenciaISOCompleta = matchFecha[1];


// --- MODIFICACIÓN CLAVE: Formatear la fecha ---
// 1. Separar la fecha de la hora usando 'T'
const soloFecha = fechaVigenciaISOCompleta.split('T')[0]; // Esto resulta en '2025-10-29'

// 2. Dividir 'YYYY-MM-DD'
const partesFecha = soloFecha.split('-');
let fechaFormateada = '';

if (partesFecha.length === 3) {
    // partesFecha[0] = YYYY, partesFecha[1] = MM, partesFecha[2] = DD
    // El formato deseado es DD/MM/YYYY
    fechaFormateada = `${partesFecha[2]}/${partesFecha[1]}/${partesFecha[0]}`;
} else {
    // En caso de que el formato cambie inesperadamente
    console.warn("La fecha extraída no tiene el formato esperado (YYYY-MM-DD).");
    fechaFormateada = soloFecha; 
}
// ------------------------------------------------

// 3. Devolver ambos resultados para el siguiente nodo
return [{
    json: {
        tasa: tasaNumerica,
        // Usamos la variable formateada
        fechaVigencia: fechaFormateada 
    }
}];
